// Set Inputs â€” Run State Recorder
const t = $input.first()?.json || {};
const str = (v) => (v === undefined || v === null) ? '' : String(v);
// Strip a leading '=' that n8n can prepend to typed Workflow Inputs crossing the
// Execute Workflow boundary. Without this, workflow='=discovery' â†’ state_key
// '=discovery_current' â†’ Google Sheets writes '#NAME?' (broken formula).
const stripEq = (v) => { let s = str(v); while (s.charAt(0) === '=') s = s.slice(1); return s; };

const databaseId = stripEq(t.database_id);
if (!databaseId) throw new Error('[Run State Set Inputs] database_id missing; the calling workflow must pass it');
const workflow = stripEq(t.workflow);
if (!workflow) throw new Error('[Run State Set Inputs] workflow missing (e.g. "discovery")');

const creditEvent = t.credit_event === true || str(t.credit_event).toLowerCase() === 'true';

return [{
  json: {
    database_id: databaseId,
    workflow,
    status: stripEq(t.status).toLowerCase(),
    run_id: stripEq(t.run_id),
    source: stripEq(t.source),
    started_at: stripEq(t.started_at),
    completed_at: stripEq(t.completed_at),
    jobs_returned: stripEq(t.jobs_returned),
    current_key: `${workflow}_current`,
    last_key: `${workflow}_last`,
    credit_event: creditEvent
  }
}];

// Build Rows â€” Run State Recorder
// running   â†’ write/refresh the current slot
// completed â†’ promote the existing current row to the last slot (preserving its
//             started_at / run_id / source), then clear the current slot.
// error     â†’ same promotion as completed, but the last slot records status 'error'
//             so failure-detection can distinguish a crash from a clean finish.
const inp = $('Set Inputs').first().json;
const existing = $('Read Current').first()?.json || {};
const dbId = inp.database_id;
const workflow = inp.workflow;

if (inp.status === 'running') {
  return [{
    json: {
      database_id: dbId,
      state_key: inp.current_key,
      workflow,
      status: 'running',
      run_id: inp.run_id,
      source: inp.source,
      started_at: inp.started_at,
      completed_at: '',
      jobs_returned: ''
    }
  }];
}

// completed | error: promote current â†’ last (preserving its identity), then clear current.
// The last slot's status reflects the terminal outcome ('completed' or 'error').
const terminalStatus = inp.status === 'error' ? 'error' : 'completed';
const startedAt = existing.started_at || inp.started_at || '';
const runId     = existing.run_id     || inp.run_id     || '';
const source    = existing.source     || inp.source     || '';

return [
  {
    json: {
      database_id: dbId,
      state_key: inp.last_key,
      workflow,
      status: terminalStatus,
      run_id: runId,
      source,
      started_at: startedAt,
      completed_at: inp.completed_at,
      jobs_returned: inp.jobs_returned
    }
  },
  {
    json: {
      database_id: dbId,
      state_key: inp.current_key,
      workflow,
      status: 'idle',
      run_id: '',
      source: '',
      started_at: '',
      completed_at: '',
      jobs_returned: ''
    }
  }
];

// Build Credit Row â€” Run State Recorder (credit_status branch)
// Maintains a SINGLE global row in credit_status via read-modify-write so the
// dashboard can answer "is there an unresolved credit problem?" with one read:
// show warning iff last_credit_event_at > last_success_at.
//
// Fires only on TERMINAL events:
//   - successful completion        â†’ refresh last_success_at (proves credit is back)
//   - credit_event === true        â†’ refresh last_credit_event_at + workflow + run_id
// A single completed-with-credit-failure run updates BOTH (jobs 1-3 saved = success,
// job 4 ran out = credit event), which correctly leaves the warning ON because the
// event timestamp will be >= the success timestamp.
// Skips: running (not terminal) and plain error (a crash, not a credit issue).
// Build Credit Row â€” Run State Recorder (credit_status branch)
// Maintains a SINGLE global row in credit_status via read-modify-write so the
// dashboard can answer "is there an unresolved credit problem?" with one read.
// NOTE: the dashboard warning is now cleared ONLY by the user's confirm button,
// which writes credit_resolved_at (show warning iff last_credit_event_at > credit_resolved_at).
// last_success_at is still maintained here for diagnostics but is NO LONGER the kill-switch.
//
// Fires only on TERMINAL events:
//   - successful completion        â†’ refresh last_success_at
//   - credit_event === true        â†’ refresh last_credit_event_at + workflow + run_id
// Skips: running (not terminal) and plain error (a crash, not a credit issue).

const inp = $('Set Inputs').first().json;
const existing = $('Read Credit Status').first()?.json || {};

const status = inp.status;
const isTerminalSuccess = (status !== 'running' && status !== 'error' && status !== '');
const isCreditEvent = inp.credit_event === true;

// Nothing credit-relevant happened on this event â†’ write nothing.
if (!isTerminalSuccess && !isCreditEvent) {
  return [];
}

const now = new Date().toISOString();

// Preserve whichever timestamp this event does NOT touch.
const lastCreditEventAt = isCreditEvent ? now : (existing.last_credit_event_at || '');
const lastCreditWorkflow = isCreditEvent ? inp.workflow : (existing.last_credit_workflow || '');
const lastCreditRunId    = isCreditEvent ? inp.run_id   : (existing.last_credit_run_id || '');
const lastSuccessAt      = isTerminalSuccess ? now : (existing.last_success_at || '');

// PRESERVE credit_resolved_at â€” written ONLY by the dashboard confirm button.
// This node must never blank it, or the next credit/success event would silently
// un-stick the user's "I've topped up" confirmation and re-show the warning.
const creditResolvedAt = existing.credit_resolved_at || '';

return [{
  json: {
    id: 'global',
    last_credit_event_at: lastCreditEventAt,
    last_credit_workflow: lastCreditWorkflow,
    last_credit_run_id: lastCreditRunId,
    last_success_at: lastSuccessAt,
    credit_resolved_at: creditResolvedAt
  }
}];

// Build Credit Error Row â€” Run State Recorder
// Appends a run_errors row when this terminal event carried a credit failure.
// run_errors is the append-only failure ledger the analytics failure chart reads;
// credit is a graceful soft-fail so the Error Trigger never fires for it â€” this is
// the deliberate write that gives credit failures a durable, countable home.
// Emits nothing unless credit_event is true (so non-credit runs add no row).

const inp = $('Set Inputs').first().json;

if (inp.credit_event !== true) {
  return [];
}

// Map the internal workflow key to the display name used in run_errors.workflow_name
// (matches the Error Trigger's prefixMap convention).
const workflowDisplay = {
  discovery: 'Job Discovery',
  application: 'Application Orchestrator',
  refinement: 'Application Refinement',
  cover_letter: 'Cover Letter Generation & Refinement'
}[inp.workflow] || inp.workflow;

return [{
  json: {
    run_id: inp.run_id,
    failed_at: new Date().toISOString(),
    workflow_name: workflowDisplay,
    workflow_id: '',
    execution_id: '',
    execution_url: '',
    last_node: '',
    error_name: 'insufficient_credit',
    error_message: 'LLM credit exhausted during run (graceful soft-fail; see credit_status banner)',
    error_stack: ''
  }
}];
